import React, { useState } from 'react';
import { useChat } from '../contexts/ChatContext';
import { useWallet } from '../contexts/WalletContext';
import { 
  MessageCircle, 
  Send, 
  Plus,
  Search,
  User,
  MapPin,
  Globe,
  Twitter
} from 'lucide-react';
import { format } from 'date-fns';

const PrivateChats = () => {
  const { privateChats, privateMessages, sendPrivateMessage } = useChat();
  const { walletAddress } = useWallet();
  const [selectedChat, setSelectedChat] = useState(privateChats[0]?.id || null);
  const [newMessage, setNewMessage] = useState('');
  const [showNewChatModal, setShowNewChatModal] = useState(false);
  const [newChatAddress, setNewChatAddress] = useState('');
  const [showProfile, setShowProfile] = useState(false);

  // Mock user profiles for demonstration
  const userProfiles = {
    '0x123456789abcdef123456789abcdef123456789a': {
      displayName: 'CryptoEnthusiast',
      bio: 'NFT collector and DeFi enthusiast. Building the future of web3.',
      avatar: 'https://via.placeholder.com/100/3b82f6/ffffff?text=CE',
      location: 'San Francisco, CA',
      website: 'https://cryptoenthusiast.com',
      twitter: '@cryptoenthusiast'
    }
  };

  const formatAddress = (address) => {
    return `${address.slice(0, 6)}...${address.slice(-4)}`;
  };

  const handleSendMessage = (e) => {
    e.preventDefault();
    if (newMessage.trim() && selectedChat) {
      sendPrivateMessage(selectedChat, newMessage.trim());
      setNewMessage('');
    }
  };

  const selectedChatMessages = selectedChat ? privateMessages[selectedChat] || [] : [];
  const selectedChatInfo = privateChats.find(chat => chat.id === selectedChat);

  const isOwnMessage = (sender) => sender === walletAddress;

  return (
    <div className="flex h-full bg-white rounded-lg shadow-sm border border-gray-200 overflow-hidden">
      {/* Chat List Sidebar */}
      <div className="w-80 border-r border-gray-200 flex flex-col">
        <div className="p-4 border-b border-gray-200">
          <div className="flex items-center justify-between mb-4">
            <h2 className="text-lg font-semibold text-gray-900">Private Chats</h2>
            <button
              onClick={() => setShowNewChatModal(true)}
              className="p-2 text-primary-600 hover:bg-primary-50 rounded-lg transition-colors duration-200"
            >
              <Plus className="w-5 h-5" />
            </button>
          </div>
          
          <div className="relative">
            <Search className="w-4 h-4 absolute left-3 top-1/2 transform -translate-y-1/2 text-gray-400" />
            <input
              type="text"
              placeholder="Search chats..."
              className="w-full pl-10 pr-4 py-2 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-primary-500 focus:border-transparent"
            />
          </div>
        </div>

        <div className="flex-1 overflow-y-auto">
          {privateChats.map((chat) => (
            <div
              key={chat.id}
              onClick={() => setSelectedChat(chat.id)}
              className={`p-4 border-b border-gray-100 cursor-pointer hover:bg-gray-50 transition-colors duration-200 ${
                selectedChat === chat.id ? 'bg-primary-50 border-primary-200' : ''
              }`}
            >
              <div className="flex items-center justify-between mb-2">
                <h3 className="font-medium text-gray-900">
                  {formatAddress(chat.participant)}
                </h3>
                {chat.unreadCount > 0 && (
                  <span className="bg-primary-600 text-white text-xs px-2 py-1 rounded-full">
                    {chat.unreadCount}
                  </span>
                )}
              </div>
              <p className="text-sm text-gray-600 truncate">{chat.lastMessage}</p>
              <p className="text-xs text-gray-500 mt-1">
                {format(chat.timestamp, 'MMM d, HH:mm')}
              </p>
            </div>
          ))}
        </div>
      </div>

      {/* Chat Area */}
      <div className="flex-1 flex flex-col">
        {selectedChat ? (
          <>
            {/* Chat Header */}
            <div className="p-4 border-b border-gray-200">
              <div className="flex items-center space-x-3">
                <div className="w-10 h-10 bg-primary-100 rounded-full flex items-center justify-center">
                  <MessageCircle className="w-5 h-5 text-primary-600" />
                </div>
                <div>
                  <h3 className="font-semibold text-gray-900">
                    {formatAddress(selectedChatInfo?.participant)}
                  </h3>
                  <p className="text-sm text-gray-500">Private conversation</p>
                </div>
              </div>
            </div>

            {/* Messages */}
            <div className="flex-1 overflow-y-auto p-4 space-y-4">
              {selectedChatMessages.map((message) => (
                <div
                  key={message.id}
                  className={`flex ${isOwnMessage(message.sender) ? 'justify-end' : 'justify-start'}`}
                >
                  <div
                    className={`max-w-xs lg:max-w-md px-4 py-2 rounded-lg ${
                      isOwnMessage(message.sender)
                        ? 'bg-primary-600 text-white'
                        : 'bg-gray-100 text-gray-900'
                    }`}
                  >
                    <p className="text-sm">{message.content}</p>
                    <p className={`text-xs mt-1 ${
                      isOwnMessage(message.sender) ? 'text-primary-200' : 'text-gray-500'
                    }`}>
                      {format(message.timestamp, 'HH:mm')}
                    </p>
                  </div>
                </div>
              ))}
            </div>

            {/* Message Input */}
            <div className="p-4 border-t border-gray-200">
              <form onSubmit={handleSendMessage} className="flex space-x-4">
                <input
                  type="text"
                  value={newMessage}
                  onChange={(e) => setNewMessage(e.target.value)}
                  placeholder="Type your message..."
                  className="flex-1 input-field"
                />
                <button
                  type="submit"
                  disabled={!newMessage.trim()}
                  className="btn-primary flex items-center space-x-2"
                >
                  <Send className="w-4 h-4" />
                  <span>Send</span>
                </button>
              </form>
            </div>
          </>
        ) : (
          <div className="flex-1 flex items-center justify-center">
            <div className="text-center">
              <MessageCircle className="w-12 h-12 text-gray-400 mx-auto mb-4" />
              <h3 className="text-lg font-medium text-gray-900 mb-2">
                Select a conversation
              </h3>
              <p className="text-gray-500">
                Choose a chat from the sidebar to start messaging
              </p>
            </div>
          </div>
        )}
      </div>

      {/* New Chat Modal */}
      {showNewChatModal && (
        <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50">
          <div className="bg-white rounded-lg p-6 w-full max-w-md">
            <h3 className="text-lg font-semibold text-gray-900 mb-4">
              Start New Chat
            </h3>
            <div className="mb-4">
              <label className="block text-sm font-medium text-gray-700 mb-2">
                Wallet Address
              </label>
              <input
                type="text"
                value={newChatAddress}
                onChange={(e) => setNewChatAddress(e.target.value)}
                placeholder="0x..."
                className="input-field"
              />
            </div>
            <div className="flex space-x-3">
              <button
                onClick={() => setShowNewChatModal(false)}
                className="flex-1 btn-secondary"
              >
                Cancel
              </button>
              <button
                onClick={() => {
                  // Mock creating new chat
                  setShowNewChatModal(false);
                  setNewChatAddress('');
                }}
                className="flex-1 btn-primary"
              >
                Start Chat
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default PrivateChats;
